create table dirkspzm32.pzm_lohnarten (
    lz_id                number(*, 0) not null enable,
    lz_lohnart           varchar2(50 char) not null enable,
    lz_uhrz_von          date,
    lz_uhrz_bis          date,
    lz_operator          varchar2(10 char),
    lz_stunden           number(*, 12),
    lz_bemerkungen       varchar2(1024 char),
    lz_alternativ_loa_id number(*, 0),
    lz_feiertag          varchar2(20 char),
    lz_wochentag         varchar2(20 char),
    lz_lohnart_grp       varchar2(50 char),
    lz_konto_bus         number(*, 5),
    lz_konto_name_kurz   varchar2(10 char),
    lz_typ               varchar2(10 char) default 'ARB_STD' not null enable,
    lz_gueltig_ab        date,
    lz_gueltig_bis       date,
    lz_einheit           varchar2(10 char) default 'HH24' not null enable,
    lz_is_erp_loa        varchar2(1 char) default 'F' not null enable,
    lz_link_loa_id       number(*, 0),
    lz_reset_monats_ende number(1, 0) default 0 not null enable,
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0)
);

alter table dirkspzm32.pzm_lohnarten
    add constraint lz_feiertag
        check ( lz_feiertag in ( 'F', 'SF' ) ) enable;

alter table dirkspzm32.pzm_lohnarten
    add constraint pk_lz_id primary key ( lz_id )
        using index enable;


